#include <vector>
#include <algorithm>
#include <climits>

using namespace std;

long long solve(vector<long long> nums) {
    int n = nums.size();
    long long max_sum = LLONG_MIN;

    // Precompute left increasing and left decreasing sequences
    vector<int> left_increasing, left_decreasing;
    for (int i = 0; i < n; ++i) {
        left_increasing.push_back(i);
        while (left_increasing.size() > 1 && nums[left_increasing.back()] <= nums[left_increasing[left_increasing.size() - 2]]) {
            left_increasing.pop_back();
        }
        left_decreasing.push_back(i);
        while (left_decreasing.size() > 1 && nums[left_decreasing.back()] >= nums[left_decreasing[left_decreasing.size() - 2]]) {
            left_decreasing.pop_back();
        }
    }

    // Precompute right increasing and right decreasing sequences
    vector<int> right_increasing, right_decreasing;
    for (int i = n - 1; i >= 0; --i) {
        right_increasing.push_back(i);
        while (right_increasing.size() > 1 && nums[right_increasing.back()] <= nums[right_increasing[right_increasing.size() - 2]]) {
            right_increasing.pop_back();
        }
        right_decreasing.push_back(i);
        while (right_decreasing.size() > 1 && nums[right_decreasing.back()] >= nums[right_decreasing[right_decreasing.size() - 2]]) {
            right_decreasing.pop_back();
        }
    }

    // Reverse to get the correct order
    reverse(left_increasing.begin(), left_increasing.end());
    reverse(left_decreasing.begin(), left_decreasing.end());
    reverse(right_increasing.begin(), right_increasing.end());
    reverse(right_decreasing.begin(), right_decreasing.end());

    // Combine sequences to find valid triplets
    for (int i = 0; i < left_increasing.size(); ++i) {
        int l = left_increasing[i];
        for (int j = 0; j < left_decreasing.size(); ++j) {
            int p = left_decreasing[j];
            if (p <= l) continue;
            for (int k = 0; k < right_increasing.size(); ++k) {
                int q = right_increasing[k];
                if (q <= p) continue;
                for (int m = 0; m < right_decreasing.size(); ++m) {
                    int r = right_decreasing[m];
                    if (r <= q) continue;
                    // Check if the triplet is valid
                    if (nums[l] < nums[p] && nums[p] > nums[q] && nums[q] < nums[r]) {
                        long long sum = nums[l] + nums[p] + nums[q] + nums[r];
                        max_sum = max(max_sum, sum);
                    }
                }
            }
        }
    }

    return max_sum;
}
